<template>
  <v-container>
    <v-row class="d-flex justify-center mb-9">
      <v-col cols="12" sm="12" md="12" lg="12">
        <v-card class="mx-auto card-table" width="100%">
          <v-data-table-server
            :headers="headers"
            :items="goods"
            v-model:options="pagination"
            v-model:page="pagination.page"
            :items-per-page="pagination.itemsPerPage"
            :items-length="pagination.itemsPerPage"
            :loading="loading"
            hide-default-footer
            fixed-header
            height="700"
            loading-text="جاري التحميل يرجى الأنتظار"
            :mobile-breakpoint="0"
          >
            <template v-slot:top>
              <v-toolbar flat color="#ffffff" class="mt-2">
                <h3 class="mx-2">جدول البضائع</h3>
                <v-divider class="mx-2" inset vertical></v-divider>
                <v-tooltip location="bottom" interactive>
                  <template v-slot:activator="{ props }">
                    <v-btn @click="reset_table" fab icon x-small v-bind="props">
                      <Icon
                        icon="solar:smartphone-update-bold"
                        color="#624fc6"
                        width="30"
                      />
                    </v-btn>
                  </template>
                  <span>تحديث معلومات الجدول</span>
                </v-tooltip>
                <v-tooltip location="bottom" interactive>
                  <template v-slot:activator="{ props }">
                    <v-btn @click="add_goods" fab icon x-small v-bind="props">
                      <Icon
                        icon="proicons:box-add"
                        color="#624fc6"
                        width="32"
                      />
                    </v-btn>
                  </template>
                  <span>اضافة بضائع</span>
                </v-tooltip>
                <v-spacer></v-spacer>
                <v-text-field
                  v-model="goods_query"
                  @input="query_change"
                  append-inner-icon="mdi-magnify"
                  label="بحث"
                  :class="display.smOnly ? 'mb-2' : ''"
                  class="font-weight-black mx-2"
                  color="#624fc6"
                  variant="outlined"
                  rounded
                  clearable
                  hide-details
                />
              </v-toolbar>
            </template>
            <template v-slot:item="{ item }">
              <tr>
                <td class="text-center font-weight-black">
                  {{ item.barcode }}
                </td>

                <td class="text-center font-weight-black">
                  {{ item.product.name }}
                </td>

                <td class="text-center font-weight-black">
                  <h4 v-if="item.product.type == 0">ملابس</h4>
                  <h4 v-else-if="item.product.type == 1">حذاء</h4>
                </td>
                <td class="text-center font-weight-black">
                  <h4>{{ item.model ?? "لايوجد" }}</h4>
                </td>

                <td class="text-center font-weight-black">
                  <v-swatches
                    v-model="item.color"
                    :disabled="true"
                  ></v-swatches>
                </td>

                <td class="text-center font-weight-black">
                  <div v-for="(item, index) in item.items" :key="index">
                    <v-sheet
                      class="mx-auto my-2"
                      style="border-radius: 16px !important"
                      :width="67"
                      :height="35"
                      :color="
                        item.status == 'available' ? '#624fc6' : '#C62828'
                      "
                      ><h4 style="padding-top: 6px">
                        {{ item.size }}
                      </h4></v-sheet
                    >
                  </div>
                </td>

                <td class="text-center font-weight-black">
                  <div v-for="(item, index) in item.items" :key="index">
                    <v-sheet
                      class="mx-auto my-2"
                      style="border-radius: 16px !important"
                      :width="67"
                      :height="35"
                      :color="
                        item.status == 'available' ? '#624fc6' : '#C62828'
                      "
                      rounded
                      ><h4 style="padding-top: 6px">
                        {{ item.quantity }}
                      </h4></v-sheet
                    >
                  </div>
                </td>
                <td class="text-center font-weight-black">
                  {{ $filters.formatNumber(item.purchase_price) }}
                </td>
                <td class="text-center font-weight-black">
                  {{ $filters.formatNumber(item.selling_price) }}
                </td>
                <td class="text-center font-weight-black">
                  {{ $moment(item.created_at).format("YYYY-MM-DD") }}
                </td>
                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        @click="pop_delete_product(item.product.id)"
                        icon
                        x-small
                        v-bind="props"
                        variant="text"
                        base-color="#C62828"
                        :loading="
                          delete_loading &&
                          id_delete_product === item.product.id
                        "
                      >
                        <Icon
                          icon="ic:round-delete-forever"
                          color="#C62828"
                          width="32"
                        />
                        <template v-slot:loader>
                          <span class="custom-loader">
                            <v-icon color="#624fc6">mdi-cached</v-icon>
                          </span>
                        </template>
                      </v-btn>
                    </template>
                    <span>حذف</span>
                  </v-tooltip>
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        @click="pop_edit_product(item)"
                        icon
                        x-small
                        v-bind="props"
                        variant="text"
                        base-color="#37474F"
                      >
                        <Icon
                          icon="material-symbols:edit-document-rounded"
                          color="#37474F"
                          width="32"
                        />
                      </v-btn>
                    </template>
                    <span>تعديل</span>
                  </v-tooltip>
                </td>
              </tr>
            </template>
          </v-data-table-server>
          <div class="text-center py-5">
            <v-row>
              <v-col cols="12" sm="6" md="7" lg="7">
                <v-pagination
                  v-model="pagination.page"
                  :length="pageCount"
                  rounded="circle"
                  variant="elevated"
                  color="#ffffff"
                  active-color="#624fc6"
                ></v-pagination>
              </v-col>
              <v-col cols="12" sm="6" md="5" lg="5">
                <v-select
                  v-model="pagination.itemsPerPage"
                  :items="items"
                  color="#624fc6"
                  variant="outlined"
                  class="font-weight-black px-2"
                  label="عدد العناصر"
                  rounded
                  persistent-hint
                ></v-select>
              </v-col>
            </v-row>
          </div>
        </v-card>
      </v-col>

      <PopAddGoods :dialog="dialog" @popClose="dialog = false" />
      <PopDeleteItems
        :dialog="dialog_delete"
        @popClose="dialog_delete = false"
        :title="title"
        @deletePorduct="delete_porduct"
      />

      <PopEditGoods
        :dialog="dialog_edit"
        @popClose="dialog_edit = false"
        :item="item_edit_product"
      />
    </v-row>
  </v-container>
</template>
<script setup>
import { ref, computed, watch } from "vue";
import { useGoodsStore } from "@/stores/goods";
// import { server } from "@/config";
import { useDisplay } from "vuetify";
import PopAddGoods from "@/components/goods/PopAddGoods.vue";
import PopDeleteItems from "@/components/layout/PopDeleteItems.vue";
import PopEditGoods from "@/components/goods/PopEditGoods.vue";

const display = useDisplay();

// Use Vuex store
const goodsStore = useGoodsStore();

const items = [5, 10, 15, 20, 25,50,100,200];

// Pagination reactive state
const pagination = ref({ page: 1, itemsPerPage: 10, sortBy: [], sortDesc: [] });

const dialog = ref(false);
const dialog_delete = ref(false);
const id_delete_product = ref(null);
const dialog_edit = ref(false);
const item_edit_product = ref(null);

const title = ref("حذف المنتج");

const headers = [
  {
    title: "باركود",
    value: "barcode",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "المنتج",
    value: "name",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "نوع",
    value: "name",
    align: "center",
    width: "180px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "موديل",
    value: "model",
    align: "center",
    width: "180px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "اللون",
    value: "color",
    align: "center",
    width: "130px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "القياس",
    value: "size",
    align: "center",
    width: "170px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "الكمية",
    value: "quantity",
    align: "center",
    width: "170px",
    headerProps: { class: "white--text text-body-1" },
  },

  {
    title: "سعر الشراء",
    value: "purchase_price",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "سعر البيع",
    value: "selling_price",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "التاريخ",
    value: "created_at",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "العمليات",
    value: "operations",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
];

// ✅ Computed properties using Pinia state
const goods_query = computed({
  get: () => goodsStore.goods_query,
  set: (val) => (goodsStore.goods_query = val),
});

const pageCount = computed(() => goodsStore.pageCount);
const goods = computed(() => goodsStore.goods);
const loading = computed(() => goodsStore.table_loading);
const delete_loading = computed(() => goodsStore.delete_product_loading);

const params = computed({
  get: () => goodsStore.params,
  set: (val) => (goodsStore.params = val),
});

// ✅ Methods
function get_goods() {
  const par = { ...pagination.value };
  params.value = par;
  goodsStore.get_goods();
}

function pop_edit_product(item) {
  dialog_edit.value = true;
  item_edit_product.value = item;
}

function pop_delete_product(id) {
  dialog_delete.value = true;
  id_delete_product.value = id;
}

const delete_porduct = async () => {
  dialog_delete.value = false;
  let data = {
    id: id_delete_product.value,
  };
  try {
    await goodsStore.delete_porduct(data);
    id_delete_product.value = null;
  } catch (e) {
    // error already handled in store
  }
};

let timerId = null;

function query_change() {
  clearTimeout(timerId);
  timerId = setTimeout(() => {
    get_goods();
    pagination.value.page = 1;
  }, 1000);
}

function reset_table() {
  goodsStore.reset_table();
  get_goods();
}

function add_goods() {
  dialog.value = true;
}

// function show_invoice(invoice) {
//   window.open(server + invoice, "_blank");
// }

// ✅ Watch pagination to refetch data
watch(
  pagination,
  () => {
    get_goods();
  },
  { deep: true }
);

watch(goods_query, (newVal) => {
  if (newVal === null || newVal === "") {
    pagination.value.page = 1;
    get_goods();
  }
});
</script>
<style scoped>
.card-table {
  box-shadow: 0px 0px 0px 0px !important;
  border-radius: 25px !important;
}
</style>
