<template>
  <v-row justify="center">
    <v-dialog
      :model-value="dialog"
      transition="dialog-bottom-transition"
      width="100%"
      height="100%"
      persistent
    >
      <v-card class="mx-auto card" width="100%">
        <v-toolbar dark color="#624fc6">
          <v-toolbar-title class="mx-auto d-flex justify-center pl-14">
            <h4 style="font-family: 'Cairo', sans-serif">الرمز السري</h4>
          </v-toolbar-title>
        </v-toolbar>
        <v-card-title class="mt-4 d-flex justify-center">
          <h4 style="color: #50535b">ادخل الرمز السري لفك القفل</h4>
        </v-card-title>
        <v-card-title class="mt-4 d-flex justify-center">
          <v-col cols="12" sm="12" md="4" lg="4" class="mx-auto">
            <v-text-field
              color="#624fc6"
              v-model="password"
              variant="outlined"
              rounded
              clearable
              class="font-weight-black pt-5"
              :type="showPassword ? 'text' : 'password'"
              label="كلمة المرور"
              autocomplete="current-password"
              :append-inner-icon="showPassword ? 'mdi-eye' : 'mdi-eye-off'"
              @click:append-inner="showPassword = !showPassword"
              :rules="PasswordsRules"
            />
          </v-col>
        </v-card-title>
        <v-card-actions class="mt-1 pb-5">
          <v-btn
            size="large"
            v-on:click="checkPassword"
            color="#624fc6"
            class="mx-auto border-btn"
            style="padding-left: 260px; padding-right: 260px"
            elevation="4"
            variant="flat"
          >
            <h4 style="color: white; font-size: 17px">تاكيد</h4>
          </v-btn>
        </v-card-actions>
      </v-card>
    </v-dialog>
  </v-row>
</template>
<script setup>
import { ref } from "vue";
import { useSnackbarStore } from "@/stores/snackbar";
const PasswordsRules = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 8 || "الحد الادنى لعدد الاحرف هوه 8",
];
const emit = defineEmits(["CheckPassword"]);


const password = ref(null);
const showPassword = ref(false);

defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
});

function checkPassword() {
  if (password.value == "fffjjjqq") {
    emit("CheckPassword", false);
  } else {
    const snackbar = useSnackbarStore();
    snackbar.showMessage({
      color: "#B71C1C",
      icon: "ri:close-circle-fill",
      text: "الرمز السري غير صحيح",
    });
  }
}
</script>
<style scoped>
.card {
  border-radius: 25px !important;
  box-shadow: 0px 0px 0px 0px !important;
}
</style>
